parameters.jsCode:
const item = $input.item.json;

// Data comes pre-enriched from CSV - just normalise field names
const followers   = Number(item.followers || item.followersCount || 0);
const username    = item.username || item.userName || '';
const engagementRate = Number(item.engagementRate || 0);

return {
  name:            item.name || item.fullName || username,
  username:        username,
  platform:        item.platform || 'Instagram',
  followers:       followers,
  avgLikes:        Number(item.avgLikes || 0),
  avgComments:     Number(item.avgComments || 0),
  engagementRate:  engagementRate,
  niche:           item.niche || 'Fitness',
  contentThemes:   item.contentThemes || 'General Fitness',
  email:           item.email || '',
  profileLink:     item.profileLink || ('https://instagram.com/' + username),
  city:            item.city || 'India',
  bio:             item.bio || '',
  segment:         item.segment || '',
  collaborationType: item.collaborationType || ''
};

parameters.text:
=You are an influencer marketing outreach specialist working for an Indian wellness brand.

Influencer Details:
- Name: {{ $json.name }}
- Platform: {{ $json.platform }}
- Followers: {{ $json.followers }}
- Engagement Rate: {{ $json.engagementRate }}%
- Niche: {{ $json.niche }}
- Content Themes: {{ $json.contentThemes }}
- City: {{ $json.city }}
- Segment: {{ $json.segment }}
- Collaboration Type: {{ $json.collaborationType }}
- Bio: {{ $json.bio }}

Generate two outreach messages. Return ONLY a raw JSON object, no markdown:

{
  "emailPitch": "60-90 words. Professional tone. Reference their niche, themes and engagement. Mention the collaboration type.",
  "instagramDM": "15-30 words. Casual and direct. Reference their content."
}

parameters.jsCode:
const item = $input.item.json;
const response = item.text || item.response || item.output || '';
let parsed;
try {
  const clean = response.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { emailPitch: 'We would love to collaborate with you!', instagramDM: 'Hi! We love your content. Let us connect!' };
}
return {
  ...item,
  emailPitch:    parsed.emailPitch    || 'We would love to collaborate with you!',
  instagramDM:   parsed.instagramDM   || 'Hi! We love your content. Let us connect!'
};
